import{_ as e,c as a,o as r,a4 as d}from"./chunks/framework.C7hkbLDc.js";const m=JSON.parse('{"title":"1.2 操作权限","description":"","frontmatter":{},"headers":[],"relativePath":"zh/1-python/1-intro/1.2-permission.md","filePath":"zh/1-python/1-intro/1.2-permission.md"}'),o={name:"zh/1-python/1-intro/1.2-permission.md"};function s(n,t,i,p,_,h){return r(),a("div",{"data-pagefind-body":!0},t[0]||(t[0]=[d('<h1 id="1-2" tabindex="-1">1.2 操作权限 <a class="header-anchor" href="#1-2" aria-label="Permalink to “1.2 操作权限”">​</a></h1><p>使用 SDK 必须在上位机获得操作权限的状态下。</p><p>若 IRC-I4A-C 系列控制柜上插有示教器，必须将示教器切换到自动模式，上位机能够连接上控制柜，并通过 SDK 使用方法 acquire_access 获得操作权限； 上位机拥有操作权限后，示教器失去操作权限，此时 PC 状态灯会亮绿色，TP 状态指示灯不亮；若示教器为手动模式，则无法获得权限，示教器具有操作权限。</p><p>若 IRC-I4A-C 系列控制柜上没插示教器，则可通过上位机直接连接 IRC-I4A-C 系列控制柜获得操作权限。</p><table tabindex="0"><thead><tr><th>系统状态指示灯及按钮</th><th>功能</th></tr></thead><tbody><tr><td>TP 状态灯</td><td>控制柜插入示教器时，该灯亮绿色，否则不亮</td></tr><tr><td>PC 状态灯</td><td>使用虚拟示教器软件 Compass 进行操作，该灯亮绿色，否则不亮</td></tr><tr><td>AUTO 状态灯</td><td>机器人的运行模式为自动运行时或示教器和 Compass 无控制权时，该灯亮绿色，否则不亮</td></tr><tr><td>TP BYPASS 按钮</td><td>拔出示教器前，若机器人是手动模式，拔出示教器后可常按此按钮将机器人切换到自动模式</td></tr></tbody></table>',5)]))}const l=e(o,[["render",s]]);export{m as __pageData,l as default};
